br>// JSON QUERY<br>SELECT * FROM product_stock<br>WHERE sku REGEXP ''^[0-9]+$'';</p><p>SELECT * FROM purchases<br>WHERE JSON_EXTRACT(additional_data, ''$.order_foreign_key'') = ''WTH240226G0126'';</p><p>SELECT * FROM <code>requests</code> <br>WHERE JSON_UNQUOTE(JSON_EXTRACT<code>content</code>, ''$.product_id'')) LIKE ''56683%''</p><p>#show port</p><p>SHOW DATABASES;</p><p>SHOW VARIABLES LIKE ''port'';<br><br>#check json gs</p><p>SELECT id<br>FROM requests<br>WHERE JSON_CONTAINS(<br>JSON_EXTRACT(content_valid, ''$[*].product_id''), <br>CAST(''53135'' AS JSON) <br>)<br>ORDER BY id desc<br>LIMIT 1;</p><p>#Update sql = notepad++</p><p>/*!50503 SET NAMES utf8mb4 */;<br><br>#lấy chữ bỏ số<br>WHERE sku REGEXP ''^[a-zA-Z]+'';<br><br>#lấy số bỏ chữ<br>WHERE sku REGEXP ''^[0-9]+$''<br><br>===========<br>LOAD DATA INFILE ''/var/lib/mysql-files/mst_rc_syouhin_mul.tsv''<br>REPLACE INTO TABLE mst_translated_syouhin_part_multi<br>FIELDS TERMINATED BY ''\t''<br>OPTIONALLY ENCLOSED BY ''"''<br>LINES TERMINATED BY ''\n'';</p><p>================</p><p>random số: FLOOR(1 + (RAND() * 50))</p><p></p>', ARRAY[], null, '2026-04-17 09:24:01.794287+00', '2026-04-17 07:25:43.309197+00', '''-9'':213,299 ''/var/lib/mysql-files/mst_rc_syouhin_mul.tsv'':303 ''0'':6,11,212,298 ''1'':48,137,272,326 ''1024'':185,186 ''192.168.55.21'':146 ''216540772'':160 ''50'':328 ''50503'':276 ''53135'':264 ''56683'':238 ''a-za-z'':287 ''addit'':220 ''applier'':20,96 ''binlog'':115 ''binlog.000097'':156 ''binlog.000132'':118 ''bỏ'':282,293 ''cast'':263 ''cbr900rr'':152 ''chang'':141 ''channel'':57,79,88 ''check'':10,36,68,247 ''chuyên'':39,71 ''chữ'':281,294 ''contain'':256 ''content'':234,259 ''count'':135 ''counter'':47 ''data'':181,198,221,301 ''databas'':175,242 ''desc'':202,270 ''duplic'':119 ''eg'':59,81,90 ''enclos'':317 ''end'':100 ''event'':116 ''execut'':112 ''extract'':219,233,258 ''field'':312 ''file'':155 ''fix'':24 ''floor'':325 ''foreign'':8,223 ''get'':167 ''global'':31,43,63 ''global.gtid'':25 